import { Pagination as ArkPagination } from "@ark-ui/react/pagination";
import { ChevronLeft, ChevronRight, Ellipsis } from "lucide-react";

import { cn } from "@/lib/utils";
import { Button } from "@/registry/thornberry/components/button";

import type { ComponentProps } from "react";

const PaginationProvider = ArkPagination.RootProvider;
const PaginationContext = ArkPagination.Context;

const PaginationRoot = ({
  className,
  ...rest
}: ComponentProps<typeof ArkPagination.Root>) => (
  <ArkPagination.Root
    className={cn("flex w-full flex-col", className)}
    {...rest}
  />
);

const PaginationEllipsis = ({
  className,
  index,
  ...rest
}: ComponentProps<typeof ArkPagination.Ellipsis>) => (
  <ArkPagination.Ellipsis
    index={index}
    className={cn("flex h-9 w-9 items-center justify-center", className)}
    {...rest}
  >
    <Ellipsis className="h-4 w-4" />
  </ArkPagination.Ellipsis>
);

const PaginationItem = ({
  className,
  page,
  ...rest
}: ComponentProps<typeof ArkPagination.Item> & { page?: number }) => (
  <ArkPagination.Item
    className={cn(
      "flex h-9 w-9 items-center justify-center rounded-md border border-input bg-background font-medium text-sm hover:bg-muted focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary data-selected:border-primary data-selected:bg-primary data-selected:text-primary-foreground data-selected:focus-visible:ring-foreground",
      className,
    )}
    {...rest}
  />
);

const PaginationPrevTrigger = ({
  className,
  ...rest
}: ComponentProps<typeof ArkPagination.PrevTrigger>) => (
  <ArkPagination.PrevTrigger asChild {...rest}>
    <Button variant="outline" size="icon" className={cn("h-9 w-9", className)}>
      <ChevronLeft className="h-4 w-4" />
    </Button>
  </ArkPagination.PrevTrigger>
);

const PaginationNextTrigger = ({
  className,
  ...rest
}: ComponentProps<typeof ArkPagination.NextTrigger>) => (
  <ArkPagination.NextTrigger asChild {...rest}>
    <Button variant="outline" size="icon" className={cn("h-9 w-9", className)}>
      <ChevronRight className="h-4 w-4" />
    </Button>
  </ArkPagination.NextTrigger>
);

export {
  PaginationRoot,
  PaginationItem,
  PaginationEllipsis,
  PaginationPrevTrigger,
  PaginationNextTrigger,
  PaginationProvider,
  PaginationContext,
};

import { ark } from "@ark-ui/react";
import { cva } from "class-variance-authority";

import { cn } from "@/lib/utils";

import type { VariantProps } from "class-variance-authority";
import type { ComponentProps } from "react";

const buttonVariants = cva(
  "inline-flex shrink-0 cursor-pointer items-center justify-center gap-2 whitespace-nowrap outline-none focus-visible:outline-none focus-visible:ring-offset-background focus-visible:ring-2 focus-visible:ring-primary focus-visible:ring-offset-2 rounded-md font-medium text-sm outline-hidden disabled:pointer-events-none disabled:opacity-50 aria-invalid:border-destructive aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 [&_svg:not([class*='size-'])]:size-4 [&_svg]:pointer-events-none [&_svg]:shrink-0 transition-[color,box-shadow,transform]",
  {
    variants: {
      variant: {
        solid:
          "bg-primary text-primary-foreground shadow-xs hover:bg-primary/90",
        outline:
          "border bg-background shadow-xs hover:bg-accent hover:text-accent-foreground",
        muted: "bg-muted text-muted-foreground shadow-xs hover:bg-muted/80",
        ghost:
          "hover:bg-accent hover:text-accent-foreground dark:hover:bg-accent/50",
        link: "text-primary underline-offset-2 hover:underline",
        destructive:
          "bg-destructive text-background shadow-xs hover:bg-destructive/90 focus-visible:ring-red-500 aria-invalid:ring-red-500/20 dark:aria-invalid:ring-red-500/40",
      },
      size: {
        sm: "h-8 gap-1.5 rounded-md px-3 has-[>svg]:px-2.5",
        md: "h-9 px-4 py-2 has-[>svg]:px-3",
        lg: "h-10 rounded-md px-6 has-[>svg]:px-4",
        icon: "size-9",
      },
    },
    defaultVariants: {
      variant: "solid",
      size: "md",
    },
  },
);

const Button = ({
  className,
  variant,
  size,
  ...rest
}: ComponentProps<typeof ark.button> & VariantProps<typeof buttonVariants>) => (
  <ark.button
    type="button"
    className={cn(buttonVariants({ variant, size }), className)}
    {...rest}
  />
);

export { Button, buttonVariants };

import { clsx } from "clsx";
import { twMerge } from "tailwind-merge";

import type { ClassValue } from "clsx";

export const cn = (...inputs: ClassValue[]) => {
  return twMerge(clsx(inputs));
};
